    S1 = #{},
    S2 = case {PMsg, NMsg} of
             {_, #{value := NFvalue}} -> S1#{value => NFvalue};
             {#{value := PFvalue}, _} -> S1#{value => PFvalue};
             _ -> S1
         end,
    S3 = case {PMsg, NMsg} of
             {_, #{timestamp := NFtimestamp}} -> S2#{timestamp => NFtimestamp};
             {#{timestamp := PFtimestamp}, _} -> S2#{timestamp => PFtimestamp};
             _ -> S2
         end,
    S4 = case {PMsg, NMsg} of
             {_, #{node_id := NFnode_id}} -> S3#{node_id => NFnode_id};
             {#{node_id := PFnode_id}, _} -> S3#{node_id => PFnode_id};
             _ -> S3
         end,
    case {PMsg, NMsg} of
        {_, #{is_tombstone := NFis_tombstone}} -> S4#{is_tombstone => NFis_tombstone};
        {#{is_tombstone := PFis_tombstone}, _} -> S4#{is_tombstone => PFis_tombstone};
        _ -> S4
    end.

