verify_msg(Msg, MsgName) when is_atom(MsgName) -> verify_msg(Msg, MsgName, []).

verify_msg(Msg, MsgName, Opts) ->
    TrUserData = proplists:get_value(user_data, Opts),
    case MsgName of
        'LwwEntry' -> v_msg_LwwEntry(Msg, [MsgName], TrUserData);
        'OrswotDots' -> v_msg_OrswotDots(Msg, [MsgName], TrUserData);
        'OrswotState' -> v_msg_OrswotState(Msg, [MsgName], TrUserData);
        'PnCounter' -> v_msg_PnCounter(Msg, [MsgName], TrUserData);
        'Request' -> v_msg_Request(Msg, [MsgName], TrUserData);
        'Response' -> v_msg_Response(Msg, [MsgName], TrUserData);
        'PutRequest' -> v_msg_PutRequest(Msg, [MsgName], TrUserData);
        'GetRequest' -> v_msg_GetRequest(Msg, [MsgName], TrUserData);
        'DeleteRequest' -> v_msg_DeleteRequest(Msg, [MsgName], TrUserData);
        'OkResponse' -> v_msg_OkResponse(Msg, [MsgName], TrUserData);
        'ValueResponse' -> v_msg_ValueResponse(Msg, [MsgName], TrUserData);
        'NotFoundResponse' -> v_msg_NotFoundResponse(Msg, [MsgName], TrUserData);
        'SetAddRequest' -> v_msg_SetAddRequest(Msg, [MsgName], TrUserData);
        'SetRemoveRequest' -> v_msg_SetRemoveRequest(Msg, [MsgName], TrUserData);
        'SetMembersRequest' -> v_msg_SetMembersRequest(Msg, [MsgName], TrUserData);
        'SetMembersResponse' -> v_msg_SetMembersResponse(Msg, [MsgName], TrUserData);
        'CounterIncrementRequest' -> v_msg_CounterIncrementRequest(Msg, [MsgName], TrUserData);
        'CounterDecrementRequest' -> v_msg_CounterDecrementRequest(Msg, [MsgName], TrUserData);
        'CounterValueRequest' -> v_msg_CounterValueRequest(Msg, [MsgName], TrUserData);
        'CounterValueResponse' -> v_msg_CounterValueResponse(Msg, [MsgName], TrUserData);
        'ErrorResponse' -> v_msg_ErrorResponse(Msg, [MsgName], TrUserData);
        _ -> mk_type_error(not_a_known_message, Msg, [])
    end.


-compile({nowarn_unused_function,v_msg_LwwEntry/3}).
-dialyzer({nowarn_function,v_msg_LwwEntry/3}).
v_msg_LwwEntry(#{} = M, Path, TrUserData) ->
    case M of
        #{value := F1} -> v_type_bytes(F1, [value | Path], TrUserData);
        _ -> ok
    end,
    case M of
        #{timestamp := F2} -> v_type_int64(F2, [timestamp | Path], TrUserData);
        _ -> ok
    end,
    case M of
        #{node_id := F3} -> v_type_string(F3, [node_id | Path], TrUserData);
        _ -> ok
    end,
    case M of
        #{is_tombstone := F4} -> v_type_bool(F4, [is_tombstone | Path], TrUserData);
        _ -> ok
    end,
    lists:foreach(fun (value) -> ok;
                      (timestamp) -> ok;
                      (node_id) -> ok;
                      (is_tombstone) -> ok;
                      (OtherKey) -> mk_type_error({extraneous_key, OtherKey}, M, Path)
                  end,
                  maps:keys(M)),
    ok;
v_msg_LwwEntry(M, Path, _TrUserData) when is_map(M) -> mk_type_error({missing_fields, [] -- maps:keys(M), 'LwwEntry'}, M, Path);
v_msg_LwwEntry(X, Path, _TrUserData) -> mk_type_error({expected_msg, 'LwwEntry'}, X, Path).

